#include <iostream>
#include <string>
using namespace std;

class Solution {
public:
    string solve(string S) {
        string ans = '';
        for (int i = 0; i < S.length(); i++) {
            if (i == 0 || S[i] != S[i-1]) ans += S[i];
        }
        return ans;
    }
};
int main() {
    string S;
    cin >> S;
    Solution solution;
    cout << solution.solve(S) << endl;
    return 0;
}
